31	use std::path::PathBuf;
32	use std::process::ExitCode;
33	
34	use rbtd::rbtdrc_crucible::{
35	    rbtdrc_lookup_fixture, rbtdrc_set_context, rbtdrc_take_context, RBTDRC_FIXTURES,
36	};
37	use rbtd::rbtdre_engine::{
38	    rbtdre_detect_colors, rbtdre_find_case, rbtdre_list_cases, rbtdre_print_summary,
39	    rbtdre_run_fixture, rbtdre_run_single_case, rbtdre_tree_clean,
40	};
41	use rbtd::rbtdri_invocation::{
42	    rbtdri_Context, rbtdri_invoke_global,
43	    RBTDRI_BURD_TEMP_DIR_KEY,
44	};
45	use rbtd::rbtdgc_consts::RBTDGC_CRUCIBLE_ACTIVE;
46	use rbtd::rbtdrm_manifest::rbtdrm_verify;
47	use rbtd::rbtdrx_platform::rbtdrx_posix_to_native;
48	
49	fn main() -> ExitCode {
50	    let args: Vec<String> = std::env::args().collect();
51	
52	    if args.get(1).map(|s| s.as_str()) == Some("single") {
53	        return rbtdb_run_single(&args[2..]);
54	    }
55	
56	    rbtdb_run_suite(&args[1..])
57	}
