99	// ── Suite runner ─────────────────────────────────────────────
100	
101	fn rbtdb_run_suite(args: &[String]) -> ExitCode {
102	    let manifest = match args.first() {
103	        Some(m) => m,
104	        None => rbtd::rbtdrg_fatal_now!(
105	            "rbtd: usage: rbtd <manifest> <fixture>\n\
106	             theurge must be launched via tabtarget (e.g. tt/rbw-tf.FixtureRun.sh tadmor)"
107	        ),
108	    };
109	
110	    let fixture = match args.get(1) {
111	        Some(n) => n,
112	        None => rbtd::rbtdrg_fatal_now!("rbtd: no fixture argument — which test fixture to run?"),
113	    };
114	
115	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
116	        rbtd::rbtdrg_fatal_now!("{}", msg);
117	    }
118	
119	    let project_root = match std::env::current_dir() {
120	        Ok(p) => p,
121	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
122	    };
123	
124	    // Run-start hygiene guard (suite only). A suite run commits a sequence of
125	    // hallmark/yoke changes; starting on a dirty tree would interleave the
126	    // operator's uncommitted edits with those commits. Single-case mode is the
127	    // crucible-debug loop and is intentionally left unguarded.
128	    if let Err(msg) = rbtdre_tree_clean(&project_root) {
129	        rbtd::rbtdrg_fatal_now!(
130	            "rbtd: refusing to start a suite run on a dirty working tree — \
131	             commit or stash first.\n{}",
132	            msg
133	        );
134	    }
135	
136	    let roots = match rbtdb_allocate_roots() {
137	        Ok(r) => r,
138	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
139	    };
140	
141	    let ctx = rbtdri_Context::new(
142	        &project_root,
143	        fixture,
144	        &roots.burv_temp_root,
145	        &roots.burv_output_root,
146	    );
147	
148	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
149	        Some(f) => f,
150	        None => rbtd::rbtdrg_fatal_now!(
151	            "rbtd: fixture '{}' has no registered Fixture — \
152	             manifest verification accepted the name but no Fixture static is bound. \
153	             Update rbtdrc_lookup_fixture in rbtdrc_crucible.rs.",
154	            fixture
155	        ),
156	    };
157	
158	    rbtdrc_set_context(ctx);
159	
160	    let colors = rbtdre_detect_colors();
161	    let run_result = rbtdre_run_fixture(fixture_def, &colors, &roots.trace_root);
162	
163	    let _ctx = rbtdrc_take_context();
164	
165	    let result = match run_result {
166	        Ok(r) => r,
167	        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: {}", msg),
168	    };
169	
170	    rbtdre_print_summary(&result, &colors);
171	
172	    if result.failed > 0 {
173	        rbtd::rbtdrg_error_now!("rbtd: {} case(s) failed", result.failed);
174	        ExitCode::FAILURE
175	    } else {
176	        ExitCode::SUCCESS
177	    }
178	}
179	
180	// ── Single-case runner ───────────────────────────────────────
181	
182	fn rbtdb_run_single(args: &[String]) -> ExitCode {
183	    let manifest = match args.first() {
184	        Some(m) => m,
185	        None => rbtd::rbtdrg_fatal_now!(
186	            "rbtd single: usage: rbtd single <manifest> <fixture> [case]\n\
187	             omit case to list all cases for the fixture"
188	        ),
189	    };
190	
191	    let fixture = match args.get(1) {
192	        Some(f) => f,
193	        None => {
194	            rbtd::rbtdrg_error_now!("rbtd single: no fixture argument");
195	            rbtdb_list_fixtures();
196	            return ExitCode::FAILURE;
197	        }
198	    };
199	
200	    if !RBTDRC_FIXTURES.iter().any(|f| f.name == *fixture) {
201	        rbtd::rbtdrg_error_now!("rbtd single: unknown fixture '{}'", fixture);
202	        rbtdb_list_fixtures();
203	        return ExitCode::FAILURE;
204	    }
205	
206	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
207	        rbtd::rbtdrg_fatal_now!("{}", msg);
208	    }
209	
210	    // Set up execution context early — needed for charge check and case execution
211	    let project_root = match std::env::current_dir() {
212	        Ok(p) => p,
213	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
214	    };
215	
216	    let roots = match rbtdb_allocate_roots() {
217	        Ok(r) => r,
218	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
219	    };
220	
221	    // Context is required for every case execution path (rbtdrc_with_ctx).
222	    // Fixtures with a setup hook (crucible charge) additionally verify their
223	    // crucible is charged externally — single-case mode never charges.
224	    let mut ctx = rbtdri_Context::new(
225	        &project_root,
226	        fixture,
227	        &roots.burv_temp_root,
228	        &roots.burv_output_root,
229	    );
230	
231	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
232	        Some(f) => f,
233	        None => rbtd::rbtdrg_fatal_now!(
234	            "rbtd single: fixture '{}' has no registered Fixture",
235	            fixture
236	        ),
237	    };
238	
239	    if fixture_def.setup.is_some() {
240	        match rbtdri_invoke_global(
241	            &mut ctx,
242	            RBTDGC_CRUCIBLE_ACTIVE,
243	            &[fixture],
244	            &[],
245	        ) {
246	            Ok(r) if r.exit_code == 0 => {}
247	            _ => rbtd::rbtdrg_fatal_now!(
248	                "rbtd single: crucible not charged for '{}'\n\
249	                 charge first: tt/rbw-cC.Charge.{}.sh",
250	                fixture, fixture
251	            ),
252	        }
253	    }
254	
255	    rbtdrc_set_context(ctx);
256	
257	    let cases = fixture_def.cases;
258	
259	    // No case argument — list all cases
260	    let case_name = match args.get(2) {
261	        None => {
262	            rbtdre_list_cases(cases);
263	            return ExitCode::SUCCESS;
264	        }
265	        Some(n) => n,
266	    };
267	
268	    // Find the case
269	    let case = match rbtdre_find_case(cases, case_name) {
270	        Some(c) => c,
271	        None => {
272	            rbtd::rbtdrg_error_now!(
273	                "rbtd single: case '{}' not found in fixture '{}'",
274	                case_name, fixture
275	            );
276	            rbtdre_list_cases(cases);
277	            return ExitCode::FAILURE;
278	        }
279	    };
280	
281	    let colors = rbtdre_detect_colors();
282	    let result = match rbtdre_run_single_case(case, &colors, &roots.trace_root) {
283	        Ok(r) => r,
284	        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: case execution error: {}", msg),
285	    };
286	
287	    rbtdre_print_summary(&result, &colors);
288	
289	    if result.failed > 0 {
290	        ExitCode::FAILURE
291	    } else {
292	        ExitCode::SUCCESS
293	    }
294	}
295	
296	fn rbtdb_list_fixtures() {
297	    rbtd::rbtdrg_info_now!("available fixtures:");
298	    for f in RBTDRC_FIXTURES {
299	        rbtd::rbtdrg_info_now!("  {}", f.name);
300	    }
301	}
