19	// RCG output discipline: all emission via rbtdrg_*! — no direct println!/eprintln!
20	
21	use std::path::Path;
22	use std::path::PathBuf;
23	
24	// ── Verdict ────────────────────────────────────────────────────
25	
26	/// Verdict from a single test case execution.
27	pub enum rbtdre_Verdict {
28	    Pass,
29	    Fail(String),
30	    Skip(String),
31	}
32	
33	// ── Disposition ────────────────────────────────────────────────
34	
35	/// Fixture disposition controls per-fixture mode policy at the engine layer.
36	///
37	/// `Independent` — cases are self-contained; suite-order is informational. Engine
38	/// permits keep-going mode for surveying.
39	///
40	/// `StateProgressing` — case N's success establishes preconditions for case N+1.
41	/// Engine refuses keep-going mode (a failed case leaves a broken precondition for
42	/// the next case, so continuing is incoherent). Fail-fast is forced.
43	#[derive(Copy, Clone, PartialEq, Eq, Debug)]
44	pub enum rbtdre_Disposition {
45	    Independent,
46	    StateProgressing,
47	}
48	
49	/// Resolve the effective fail-fast bool from a disposition and a caller's
50	/// requested keep-going mode. Returns Err if the request is incompatible with
51	/// the disposition (StateProgressing + keep-going).
52	///
53	/// Centralizes the keep-going / fail-fast policy at the engine boundary so all
54	/// callers funnel through one place.
55	pub fn rbtdre_resolve_fail_fast(
56	    disposition: rbtdre_Disposition,
57	    keep_going_requested: bool,
58	) -> Result<bool, String> {
59	    match (disposition, keep_going_requested) {
60	        (rbtdre_Disposition::StateProgressing, true) => Err(
61	            "rbtd: keep-going mode refused for StateProgressing fixture — \
62	             a failed case leaves a broken precondition for the next case, \
63	             so continuing is incoherent. Run individual cases via the \
64	             SingleCase tabtarget if you want to survey."
65	                .to_string(),
66	        ),
67	        (rbtdre_Disposition::StateProgressing, false) => Ok(true),
68	        (rbtdre_Disposition::Independent, keep_going) => Ok(!keep_going),
69	    }
70	}
71	
72	// ── Working-tree hygiene ───────────────────────────────────────
73	
74	/// Returns Ok(()) when the working tree rooted at `root` is clean
75	/// (`git status --porcelain` empty); Err with a human diagnostic when the tree
76	/// carries uncommitted changes or git itself fails. Shared by the pristine
77	/// fixture's Class-A check and the suite run-start hygiene guard so both express
78	/// "clean tree" through one implementation.
79	pub fn rbtdre_tree_clean(root: &Path) -> Result<(), String> {
80	    match std::process::Command::new("git")
81	        .args(["status", "--porcelain"])
82	        .current_dir(root)
83	        .output()
84	    {
85	        Ok(out) if out.status.success() => {
86	            let stdout = String::from_utf8_lossy(&out.stdout);
87	            let trimmed = stdout.trim();
88	            if trimmed.is_empty() {
89	                Ok(())
90	            } else {
91	                Err(format!(
92	                    "working tree not clean — uncommitted changes:\n{}",
93	                    trimmed
94	                ))
95	            }
96	        }
97	        Ok(out) => Err(format!(
98	            "git status --porcelain failed (exit {}): {}",
99	            out.status.code().unwrap_or(-1),
100	            String::from_utf8_lossy(&out.stderr).trim()
101	        )),
102	        Err(e) => Err(format!("git status invocation failed: {}", e)),
103	    }
104	}
105	
106	// ── Case and Fixture ───────────────────────────────────────────
107	
108	/// A named test case with a function that receives its isolated temp directory.
109	/// The `name` field holds the raw stringified function name (from the `case!` macro).
110	pub struct rbtdre_Case {
111	    pub name: &'static str,
112	    pub func: fn(&Path) -> rbtdre_Verdict,
113	}
114	
115	/// A complete fixture definition — name, disposition, optional setup/teardown
116	/// hooks, and case array.
117	///
118	/// `setup` runs before any cases. Failure aborts the fixture; cases do not run;
119	/// `teardown` still runs (finally-shaped) for any partial-state cleanup.
120	///
121	/// `teardown` runs unconditionally after cases regardless of case verdicts or
122	/// setup outcome. Errors are surfaced as warnings — teardown is best-effort.
123	///
124	/// Both hooks access invocation context via the thread-local established by
125	/// `rbtdrc_set_context` before `rbtdre_run_fixture` is called.
126	pub struct rbtdre_Fixture {
127	    pub name: &'static str,
128	    pub disposition: rbtdre_Disposition,
129	    pub setup: Option<fn() -> Result<(), String>>,
130	    pub teardown: Option<fn()>,
131	    pub cases: &'static [rbtdre_Case],
132	}
133	
134	/// Case registration macro. Derives case name from function name via `stringify!`.
135	/// Compiler enforces uniqueness — duplicate function names won't compile.
136	#[macro_export]
137	macro_rules! case {
138	    ($func:path) => {
139	        $crate::rbtdre_engine::rbtdre_Case {
140	            name: stringify!($func),
141	            func: $func,
142	        }
143	    };
144	}
145	
146	// ── Colors ─────────────────────────────────────────────────────
147	
148	/// Terminal color codes, empty strings when color is disabled.
149	pub struct rbtdre_Colors {
150	    pub green: &'static str,
151	    pub red: &'static str,
152	    pub yellow: &'static str,
153	    pub reset: &'static str,
154	}
155	
156	/// Detect terminal color support from TERM environment variable.
157	pub fn rbtdre_detect_colors() -> rbtdre_Colors {
158	    match std::env::var("TERM") {
159	        Ok(term) if !term.is_empty() && term != "dumb" => rbtdre_Colors {
160	            green: "\x1b[1;32m",
161	            red: "\x1b[1;31m",
162	            yellow: "\x1b[1;33m",
163	            reset: "\x1b[0m",
164	        },
165	        _ => rbtdre_Colors {
166	            green: "",
167	            red: "",
168	            yellow: "",
169	            reset: "",
170	        },
171	    }
172	}
173	
174	// ── Trace ──────────────────────────────────────────────────────
175	
176	/// Write verdict and detail to a trace file in the case temp directory.
177	fn rbtdre_write_trace(case_dir: &Path, display_name: &str, verdict: &rbtdre_Verdict) {
178	    let content = match verdict {
179	        rbtdre_Verdict::Pass => format!("PASSED: {}\n", display_name),
180	        rbtdre_Verdict::Fail(detail) => format!("FAILED: {}\n\n{}\n", display_name, detail),
181	        rbtdre_Verdict::Skip(reason) => {
182	            format!("SKIPPED: {}\n\nReason: {}\n", display_name, reason)
183	        }
184	    };
185	    let _ = std::fs::write(case_dir.join("trace.txt"), content);
186	}
187	
188	// ── Dispatch ───────────────────────────────────────────────────
189	
190	/// Aggregate results from running a fixture's cases.
191	pub struct rbtdre_RunResult {
192	    pub passed: usize,
193	    pub failed: usize,
194	    pub skipped: usize,
195	    pub temp_dir: PathBuf,
196	}
197	
198	/// Run all cases sequentially, dispatching each with per-case temp dir isolation.
199	pub fn rbtdre_run_cases(
200	    cases: &[rbtdre_Case],
201	    colors: &rbtdre_Colors,
202	    fail_fast: bool,
203	    root_temp: &Path,
204	) -> Result<rbtdre_RunResult, String> {
205	    let mut passed = 0usize;
206	    let mut failed = 0usize;
207	    let mut skipped = 0usize;
208	
209	    for case in cases {
210	        let case_dir = root_temp.join(case.name);
211	        std::fs::create_dir_all(&case_dir).map_err(|e| {
212	            format!("rbtd: failed to create case dir '{}': {}", case.name, e)
213	        })?;
214	
215	        let verdict = (case.func)(&case_dir);
216	        rbtdre_write_trace(&case_dir, case.name, &verdict);
217	
218	        match &verdict {
219	            rbtdre_Verdict::Pass => {
220	                crate::rbtdrg_info_now!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
221	                passed += 1;
222	            }
223	            rbtdre_Verdict::Fail(_) => {
224	                crate::rbtdrg_info_now!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
225	                failed += 1;
226	                if fail_fast {
227	                    break;
228	                }
229	            }
230	            rbtdre_Verdict::Skip(_) => {
231	                crate::rbtdrg_info_now!(
232	                    "{}SKIPPED:{} {}",
233	                    colors.yellow, colors.reset, case.name
234	                );
235	                skipped += 1;
236	            }
237	        }
238	    }
239	
240	    Ok(rbtdre_RunResult {
241	        passed,
242	        failed,
243	        skipped,
244	        temp_dir: root_temp.to_path_buf(),
245	    })
246	}
247	
248	/// Print colored summary line and trace directory location.
249	pub fn rbtdre_print_summary(result: &rbtdre_RunResult, colors: &rbtdre_Colors) {
250	    let total = result.passed + result.failed + result.skipped;
251	    let (color, end_color) = if result.failed > 0 {
252	        (colors.red, colors.reset)
253	    } else {
254	        (colors.green, colors.reset)
255	    };
256	
257	    crate::rbtdrg_info_now!(
258	        "{}{} passed, {} failed, {} skipped ({} total){}",
259	        color, result.passed, result.failed, result.skipped, total, end_color,
260	    );
261	    crate::rbtdrg_info_now!("Trace dir: {}", result.temp_dir.display());
262	}
263	
264	// ── Single-case operations ───────────────────────────────────
265	
266	/// Find a case by name in a flat case array.
267	pub fn rbtdre_find_case<'a>(
268	    cases: &'a [rbtdre_Case],
269	    target: &str,
270	) -> Option<&'a rbtdre_Case> {
271	    cases.iter().find(|c| c.name == target)
272	}
273	
274	/// List all cases by name.
275	pub fn rbtdre_list_cases(cases: &[rbtdre_Case]) {
276	    for case in cases {
277	        crate::rbtdrg_info_now!("  {}", case.name);
278	    }
279	}
280	
281	/// Run a fixture: setup hook → cases → teardown hook (finally-shaped).
282	///
283	/// Expects the invocation context to already be installed in the thread-local
284	/// (via `rbtdrc_set_context`); setup/teardown access ctx via that channel.
285	///
286	/// Setup failure short-circuits cases but still invokes teardown. Teardown
287	/// errors are surfaced as warnings via stderr; the function never panics on
288	/// teardown failure.
289	pub fn rbtdre_run_fixture(
290	    fixture: &'static rbtdre_Fixture,
291	    colors: &rbtdre_Colors,
292	    root_temp: &Path,
293	) -> Result<rbtdre_RunResult, String> {
294	    let setup_result = match fixture.setup {
295	        Some(f) => f(),
296	        None => Ok(()),
297	    };
298	
299	    let run_result = match setup_result {
300	        Ok(()) => {
301	            let fail_fast = rbtdre_resolve_fail_fast(fixture.disposition, false)
302	                .expect("disposition-default mode never fails policy resolution");
303	            rbtdre_run_cases(fixture.cases, colors, fail_fast, root_temp)
304	        }
305	        Err(msg) => Err(format!("rbtd: fixture '{}' setup failed: {}", fixture.name, msg)),
306	    };
307	
308	    if let Some(f) = fixture.teardown {
309	        f();
310	    }
311	
312	    run_result
313	}
314	
315	/// Run a single case without charge/quench lifecycle.
316	pub fn rbtdre_run_single_case(
317	    case: &rbtdre_Case,
318	    colors: &rbtdre_Colors,
319	    root_temp: &Path,
320	) -> Result<rbtdre_RunResult, String> {
321	    let case_dir = root_temp.join(case.name);
322	    std::fs::create_dir_all(&case_dir)
323	        .map_err(|e| format!("rbtd: failed to create case dir '{}': {}", case.name, e))?;
324	
325	    let verdict = (case.func)(&case_dir);
326	    rbtdre_write_trace(&case_dir, case.name, &verdict);
327	
328	    let (passed, failed, skipped) = match &verdict {
329	        rbtdre_Verdict::Pass => {
330	            crate::rbtdrg_info_now!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
331	            (1, 0, 0)
332	        }
333	        rbtdre_Verdict::Fail(_) => {
334	            crate::rbtdrg_info_now!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
335	            (0, 1, 0)
336	        }
337	        rbtdre_Verdict::Skip(_) => {
338	            crate::rbtdrg_info_now!("{}SKIPPED:{} {}", colors.yellow, colors.reset, case.name);
339	            (0, 0, 1)
340	        }
341	    };
342	
343	    Ok(rbtdre_RunResult {
344	        passed,
345	        failed,
346	        skipped,
347	        temp_dir: root_temp.to_path_buf(),
348	    })
349	}
