50	fn rbtdtl_run_case(fixture: &'static str, case_name: &str) -> (rbtdre_Verdict, PathBuf) {
51	    let fix = rbtdrc_lookup_fixture(fixture)
52	        .unwrap_or_else(|| panic!("fixture '{}' not registered", fixture));
