12	// See the License for the specific language governing permissions and
13	// limitations under the License.
14	//
15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTDRL — calibrant fixtures: synthetic test inputs with deterministic
18	// verdicts that exercise the operator-facing surface of the theurge engine.
19	// Internal framework-test plumbing; not end-user-facing.
20	//
21	// Four fixtures registered through rbtdrm_manifest.rs and dispatched via
22	// rbtdrc_crucible.rs:
23	//
24	//   calibrant-verdicts      Independent       4 cases   verdict-path coverage
25	//   calibrant-fail-fast     Independent       3 cases   fail-fast halts subsequent cases
26	//   calibrant-progressing   StateProgressing  2 cases   probe Ok/Err dispatch
27	//   calibrant-sentinel      Independent       1 case    suite-fail-fast pivot
28	//
29	// All four declare empty rbtdrm_required_colophons — calibrant cases never
30	// shell out to bash tabtargets, so the manifest-coupling check is vacuous.
31	//
32	// A bash blackbox testbench consumes these fixtures and asserts engine-output
33	// contracts (exit codes, stderr format, fail-fast semantics, disposition ×
34	// keep-going policy gate).
35	
36	use std::path::Path;
37	
38	use crate::case;
39	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
40	use crate::rbtdre_engine::{rbtdre_Case, rbtdre_Disposition, rbtdre_Fixture, rbtdre_Verdict};
41	use crate::rbtdrm_manifest::{
42	    RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST, RBTDRM_FIXTURE_CALIBRANT_PROGRESSING,
43	    RBTDRM_FIXTURE_CALIBRANT_SENTINEL, RBTDRM_FIXTURE_CALIBRANT_VERDICTS,
44	};
45	
46	/// Sentinel filename written into a case's temp dir to mark execution. The
47	/// blackbox driver asserts presence/absence by globbing under the
48	/// BURV_TEMP_ROOT_DIR it set for the rbtd invocation. I/O failure during
49	/// sentinel write fails the case visibly — silent failure would hide bugs in
50	/// the engine's case-dir contract.
51	pub(crate) const RBTDRL_SENTINEL_FILE: &str = "ran.sentinel";
52	
53	/// Case-written output filename. Distinct from the engine's auto-written
54	/// trace.txt so the blackbox driver can verify both the engine's per-case
55	/// trace contract and the case's own write contract.
56	pub(crate) const RBTDRL_OUTPUT_FILE: &str = "output.txt";
57	
58	fn rbtdrl_write_sentinel(dir: &Path) -> Result<(), rbtdre_Verdict> {
59	    std::fs::write(dir.join(RBTDRL_SENTINEL_FILE), "")
60	        .map_err(|e| rbtdre_Verdict::Fail(format!("sentinel write failed: {}", e)))
61	}
62	
63	// ── calibrant-verdicts ──────────────────────────────────────
64	
65	fn rbtdrl_verdicts_pass(_dir: &Path) -> rbtdre_Verdict {
66	    rbtdre_Verdict::Pass
67	}
68	
69	fn rbtdrl_verdicts_fail(_dir: &Path) -> rbtdre_Verdict {
70	    rbtdre_Verdict::Fail("calibrant deterministic fail verdict".to_string())
71	}
72	
73	fn rbtdrl_verdicts_skip(_dir: &Path) -> rbtdre_Verdict {
74	    rbtdre_Verdict::Skip("calibrant deterministic skip verdict".to_string())
75	}
76	
77	fn rbtdrl_verdicts_pass_with_output(dir: &Path) -> rbtdre_Verdict {
78	    if let Err(e) = std::fs::write(
79	        dir.join(RBTDRL_OUTPUT_FILE),
80	        "calibrant case-written output\n",
81	    ) {
82	        return rbtdre_Verdict::Fail(format!("output write failed: {}", e));
83	    }
84	    rbtdre_Verdict::Pass
85	}
86	
87	pub static RBTDRL_CASES_VERDICTS: &[rbtdre_Case] = &[
88	    case!(rbtdrl_verdicts_pass),
89	    case!(rbtdrl_verdicts_fail),
90	    case!(rbtdrl_verdicts_skip),
91	    case!(rbtdrl_verdicts_pass_with_output),
92	];
93	
94	// ── calibrant-fail-fast ─────────────────────────────────────
95	
96	fn rbtdrl_failfast_pass(_dir: &Path) -> rbtdre_Verdict {
97	    rbtdre_Verdict::Pass
98	}
99	
100	fn rbtdrl_failfast_fail(_dir: &Path) -> rbtdre_Verdict {
101	    rbtdre_Verdict::Fail("calibrant fail-fast fail trigger".to_string())
102	}
103	
104	/// Trailing case after the deterministic fail. Under default fail-fast it
105	/// never runs and its sentinel must be absent; under keep-going it runs and
106	/// writes the sentinel.
107	fn rbtdrl_failfast_not_reached(dir: &Path) -> rbtdre_Verdict {
108	    if let Err(v) = rbtdrl_write_sentinel(dir) {
109	        return v;
110	    }
111	    rbtdre_Verdict::Pass
112	}
113	
114	pub static RBTDRL_CASES_FAIL_FAST: &[rbtdre_Case] = &[
115	    case!(rbtdrl_failfast_pass),
116	    case!(rbtdrl_failfast_fail),
117	    case!(rbtdrl_failfast_not_reached),
118	];
119	
120	// ── calibrant-progressing ───────────────────────────────────
121	
122	/// Probe-Ok mechanism: deterministic Ok return. No env-var or file coupling
123	/// — a single fixture run exercises the case-body-runs-after-Probe-Ok path.
124	fn rbtdrl_probe_ok() -> Result<(), String> {
125	    Ok(())
126	}
127	
128	/// Probe-Err mechanism: deterministic Err return. Case body never runs, so a
129	/// single fixture run exercises the Fail-via-Probe-Err path. Required by the
130	/// blackbox driver to verify rbtdrb_assert's "precondition '%s' not met:" +
131	/// "remediation:" stderr format.
132	fn rbtdrl_probe_err() -> Result<(), String> {
133	    Err("calibrant deterministic probe failure".to_string())
134	}
135	
136	fn rbtdrl_progressing_probe_ok(_dir: &Path) -> rbtdre_Verdict {
137	    let probe = rbtdrb_Probe {
138	        name: "calibrant deterministic ok",
139	        check: rbtdrl_probe_ok,
140	        remediation: "n/a — deterministic probe always Ok",
141	    };
142	    if let Err(v) = rbtdrb_assert(&probe) {
143	        return v;
144	    }
145	    rbtdre_Verdict::Pass
146	}
147	
148	fn rbtdrl_progressing_probe_err(_dir: &Path) -> rbtdre_Verdict {
149	    let probe = rbtdrb_Probe {
150	        name: "calibrant deterministic err",
151	        check: rbtdrl_probe_err,
152	        remediation: "n/a — deterministic probe always Err for engine surface verification",
153	    };
154	    if let Err(v) = rbtdrb_assert(&probe) {
155	        return v;
156	    }
157	    rbtdre_Verdict::Fail("calibrant probe-err case body executed unexpectedly".to_string())
158	}
159	
160	pub static RBTDRL_CASES_PROGRESSING: &[rbtdre_Case] = &[
161	    case!(rbtdrl_progressing_probe_ok),
162	    case!(rbtdrl_progressing_probe_err),
163	];
164	
165	// ── calibrant-sentinel ──────────────────────────────────────
166	
167	/// Single-case Independent fixture used as a suite-level fail-fast pivot:
168	/// place this fixture after a failing fixture in the calibrant suite and
169	/// assert the sentinel is absent.
170	fn rbtdrl_sentinel_marks(dir: &Path) -> rbtdre_Verdict {
171	    if let Err(v) = rbtdrl_write_sentinel(dir) {
172	        return v;
173	    }
174	    rbtdre_Verdict::Pass
